DROP TABLE IF EXISTS `access_history`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `access_history` (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT 'UID',
  `created` datetime DEFAULT NULL COMMENT '생성시간',
  `user_id` varchar(48) DEFAULT NULL COMMENT '유저 ID',
  `type` tinyint(1) DEFAULT NULL COMMENT '로그인 유형',
  `update_time` datetime DEFAULT NULL COMMENT '사용자 접속 시간',
  `ip_addr` varchar(20) DEFAULT NULL COMMENT '사용자 접속 IP',
  `os_ver` varchar(20) DEFAULT NULL COMMENT '사용자 접속 OS 버전',
  `browser_ver` varchar(20) DEFAULT NULL COMMENT '사용자 접속 브라우져 버전',
  `fk_user_id` int(11) DEFAULT NULL COMMENT '사용자테이블 FK',
  PRIMARY KEY (`id`),
  KEY `fk_user_id` (`fk_user_id`),
  CONSTRAINT `access_history_ibfk_1` FOREIGN KEY (`fk_user_id`) REFERENCES `users` (`id`),
  CONSTRAINT `CONSTRAINT_1` CHECK (`type` in (0,1))
) ENGINE=InnoDB AUTO_INCREMENT=981 DEFAULT CHARSET=utf8 COLLATE=utf8_general_ci COMMENT='접속 이력';
