DROP TABLE IF EXISTS `approval_management`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `approval_management` (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT 'UID',
  `created` datetime NOT NULL DEFAULT current_timestamp() COMMENT '생성시간',
  `request_date` datetime DEFAULT NULL COMMENT '요청일자',
  `request_number` varchar(48) DEFAULT NULL COMMENT '요청번호',
  `request_path` varchar(256) DEFAULT NULL COMMENT '요청경로',
  `request_path_id` int(11) DEFAULT NULL COMMENT '요청경로',
  `request_name` varchar(48) DEFAULT NULL COMMENT '요청자',
  `approval_leader` varchar(48) DEFAULT NULL COMMENT '결재팀장',
  `approval_status` varchar(48) DEFAULT NULL COMMENT '결재상태',
  `reject_reason` varchar(256) DEFAULT NULL COMMENT '반려사유',
  `approval_date` datetime DEFAULT NULL COMMENT '결재일자',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=13 DEFAULT CHARSET=utf8 COLLATE=utf8_general_ci COMMENT='전자결재관리';
