-- Table structure for table `base_client_item`
--

DROP TABLE IF EXISTS `base_client_item`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `base_client_item` (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT 'UID',
  `created` datetime DEFAULT NULL COMMENT '생성시간',
  `client_item_code` varchar(48) DEFAULT NULL COMMENT '거래처품번',
  `unit_price_type` varchar(48) DEFAULT NULL COMMENT '단가구분',
  `unit_price` decimal(12,2) DEFAULT NULL,
  `main_supplier` tinyint(1) DEFAULT NULL COMMENT '주공급업체',
  `note` varchar(256) DEFAULT NULL COMMENT '참고',
  `etc` text DEFAULT NULL COMMENT '비고',
  `item_code` varchar(48) DEFAULT NULL COMMENT '품목코드',
  `client_id` int(11) DEFAULT NULL COMMENT '고객 ID',
  `fk_company_id` int(11) DEFAULT NULL COMMENT '회사테이블 FK',
  PRIMARY KEY (`id`),
  KEY `item_code` (`item_code`),
  KEY `client_id` (`client_id`),
  KEY `fk_company_id` (`fk_company_id`),
  CONSTRAINT `base_client_item_ibfk_1` FOREIGN KEY (`item_code`) REFERENCES `base_item` (`item_code`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `base_client_item_ibfk_2` FOREIGN KEY (`client_id`) REFERENCES `base_client` (`id`),
  CONSTRAINT `base_client_item_ibfk_3` FOREIGN KEY (`fk_company_id`) REFERENCES `companies` (`id`),
  CONSTRAINT `CONSTRAINT_1` CHECK (`main_supplier` in (0,1))
) ENGINE=InnoDB AUTO_INCREMENT=1825 DEFAULT CHARSET=utf8 COLLATE=utf8_general_ci COMMENT='기준정보(품목관리-거래처품목코드)';
/*!40101 SET character_set_client = @saved_cs_client */;

