--
-- Table structure for table `base_item`
--

DROP TABLE IF EXISTS `base_item`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `base_item` (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT 'UID',
  `created` datetime DEFAULT NULL COMMENT '생성시간',
  `item_code` varchar(48) DEFAULT NULL COMMENT '품목코드',
  `item_name` varchar(128) DEFAULT NULL COMMENT '품명',
  `item_standard` varchar(128) DEFAULT NULL COMMENT '규격',
  `asset_type` varchar(48) DEFAULT NULL COMMENT '자산구분',
  `item_group` varchar(128) DEFAULT NULL COMMENT '품목 그룹',
  `main_category` varchar(48) DEFAULT NULL COMMENT '품목관리 대분류',
  `middle_category` varchar(48) DEFAULT NULL COMMENT '품목관리 중분류',
  `sub_category` varchar(48) DEFAULT NULL COMMENT '품목관리 소분류',
  `delivery_date` varchar(48) DEFAULT NULL COMMENT '표준 납기일',
  `item_detail` varchar(48) DEFAULT NULL COMMENT '품목설명',
  `color_type` varchar(48) DEFAULT NULL COMMENT '지원색상',
  `dot_number` varchar(48) DEFAULT NULL COMMENT 'Dot 구성',
  `dot_pitch` varchar(48) DEFAULT NULL COMMENT 'Dot Pitch',
  `module_size` varchar(48) DEFAULT NULL COMMENT '모듈크기',
  `dot_size` varchar(48) DEFAULT NULL COMMENT '필셀크기',
  `drive_mode` varchar(48) DEFAULT NULL COMMENT '고동 모드',
  `in_out_point` varchar(48) DEFAULT NULL COMMENT '적용장소',
  `brightness` varchar(48) DEFAULT NULL COMMENT '밝기(cd/m2)',
  `watt` varchar(48) DEFAULT NULL COMMENT '소비전력(w)',
  `etc` text DEFAULT NULL COMMENT '비고',
  `safety_stock` int(11) DEFAULT 0 COMMENT '안전재고',
  `unit` varchar(10) DEFAULT NULL COMMENT '단위',
  `sales_price` bigint(20) DEFAULT 0 COMMENT '매출단가',
  `purchase_price` decimal(12,2) DEFAULT NULL,
  `cost_price` decimal(10,2) DEFAULT 0.00 COMMENT '마감원가',
  `note1` varchar(256) DEFAULT NULL COMMENT '참고1',
  `note2` varchar(256) DEFAULT NULL COMMENT '참고2',
  `item_img` mediumtext DEFAULT NULL COMMENT '품목이미지',
  `moq` int(11) DEFAULT 0 COMMENT 'MOQ',
  `packing_quantity` int(11) DEFAULT NULL COMMENT '포장단위수량',
  `transfer_quantity` int(11) DEFAULT NULL COMMENT '이송단위수량',
  `import_check` tinyint(1) DEFAULT 0 COMMENT '수입검사',
  `shipment_check` tinyint(1) DEFAULT 0 COMMENT '출하검사',
  `lot_check` tinyint(1) DEFAULT 0 COMMENT 'LOT관리',
  `before_item_code` varchar(48) DEFAULT NULL COMMENT '변경전품목코드',
  `after_item_code` varchar(48) DEFAULT NULL COMMENT '변경후품목코드',
  `end_of_use` tinyint(1) DEFAULT 0 COMMENT '사용종료',
  `end_date` datetime DEFAULT NULL COMMENT '종료일자',
  `hs_code` varchar(128) DEFAULT NULL COMMENT 'HSCode',
  `register_id` varchar(48) DEFAULT NULL COMMENT '최초등록자',
  `modify_id` varchar(48) DEFAULT NULL COMMENT '최종수정자',
  `modify_date` datetime DEFAULT NULL COMMENT '최종수정일자',
  `bom_yn` tinyint(1) DEFAULT 0 COMMENT 'BOM 여부',
  `fk_manufacturer_client_id` int(11) DEFAULT NULL COMMENT '제조업체 FK',
  `fk_company_id` int(11) DEFAULT NULL COMMENT '회사테이블 FK',
  PRIMARY KEY (`id`),
  UNIQUE KEY `item_code` (`item_code`),
  KEY `fk_manufacturer_client_id` (`fk_manufacturer_client_id`),
  KEY `fk_company_id` (`fk_company_id`),
  CONSTRAINT `base_item_ibfk_1` FOREIGN KEY (`fk_manufacturer_client_id`) REFERENCES `base_client` (`id`),
  CONSTRAINT `base_item_ibfk_2` FOREIGN KEY (`fk_company_id`) REFERENCES `companies` (`id`),
  CONSTRAINT `CONSTRAINT_1` CHECK (`import_check` in (0,1)),
  CONSTRAINT `CONSTRAINT_2` CHECK (`shipment_check` in (0,1)),
  CONSTRAINT `CONSTRAINT_3` CHECK (`lot_check` in (0,1)),
  CONSTRAINT `CONSTRAINT_4` CHECK (`end_of_use` in (0,1)),
  CONSTRAINT `CONSTRAINT_5` CHECK (`bom_yn` in (0,1))
) ENGINE=InnoDB AUTO_INCREMENT=1407 DEFAULT CHARSET=utf8 COLLATE=utf8_general_ci COMMENT='기준정보(품목관리)';
/*!40101 SET character_set_client = @saved_cs_client */;

