  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT 'UID',
  `created` datetime DEFAULT NULL COMMENT '생성시간',
  `business_number` varchar(64) DEFAULT NULL COMMENT '영업번호',
  `business_name` varchar(128) DEFAULT NULL COMMENT '영업건명',
  `business_date` datetime DEFAULT NULL COMMENT '영업일자',
  `client_company` varchar(128) DEFAULT NULL COMMENT '고객업체명',
  `client_manager` varchar(48) DEFAULT NULL COMMENT '업체담당자',
  `contract_company` varchar(48) DEFAULT NULL COMMENT '원청업체',
  `business_amount` bigint(20) DEFAULT NULL COMMENT '영업금액',
  `rate` float DEFAULT NULL COMMENT '요율',
  `gross_profit` bigint(20) DEFAULT NULL COMMENT '매출총이익',
  `gross_profit_rate` float DEFAULT NULL COMMENT 'GP (매출총이익률)',
  `operating_profit` bigint(20) DEFAULT NULL COMMENT '순수익',
  `operating_profit_rate` float DEFAULT NULL COMMENT 'OP (순수익률)',
  `business_department` varchar(48) DEFAULT NULL COMMENT '담당부서',
  `business_manager` varchar(48) DEFAULT NULL COMMENT '당사담당자',
  `business_type` varchar(48) DEFAULT NULL COMMENT '영업구분',
  `classification` varchar(48) DEFAULT NULL COMMENT '종목',
  `delivery_type` varchar(48) DEFAULT NULL COMMENT '납품형태',
  `location` varchar(48) DEFAULT NULL COMMENT '지역',
  `registration_closing_date` datetime DEFAULT NULL COMMENT '등록마감',
  `bid_closing_date` datetime DEFAULT NULL COMMENT '투찰마감',
  `business_status` varchar(48) DEFAULT NULL COMMENT '현재단계',
  `completion_date` datetime DEFAULT NULL COMMENT '준공일자',
  `business_progress` varchar(48) DEFAULT NULL COMMENT '진행현황',
  `business_important` varchar(48) DEFAULT NULL COMMENT '중요',
  `contract_type` varchar(48) DEFAULT NULL COMMENT '계약유형',
  `modify_manager` varchar(48) DEFAULT NULL COMMENT '최종수정자',
  `modify_date` datetime DEFAULT NULL COMMENT '최종수정일자',
  `fk_project_management_id` int(11) DEFAULT NULL COMMENT '프로젝트 FK',
  `fk_company_id` int(11) DEFAULT NULL COMMENT '회사 FK',
  PRIMARY KEY (`id`),
  KEY `fk_company_id` (`fk_company_id`),
  CONSTRAINT `project_business_ibfk_1` FOREIGN KEY (`fk_company_id`) REFERENCES `companies` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=634 DEFAULT CHARSET=utf8 COLLATE=utf8_general_ci COMMENT='영업관리(영업등록)';
/*!40101 SET character_set_client = @saved_cs_client */;

