INSERT INTO `project_business_note` VALUES (1,'2025-04-22 17:44:02','2025-04-22 17:20:58','김민규','감시반 이전에 따른 당사 X-BOX 이전설치 필요',546),(2,'2025-04-22 17:44:02','2025-04-22 17:27:42','김민규','이전과 동일하게 하이엠과 협업',546),(3,'2025-04-22 17:44:02','2025-04-22 17:27:50','김민규','직생관리 철저 (대외비), 3자가 본 사업을 예의주시 하고 있을 수 있음',546),(4,'2025-04-22 17:59:36','2025-04-22 17:57:48','김민규','※당사 보험료(건강,연금,노인,퇴직) 정산시, 하이엠도 동일요율로 정산조건입니다',546),(5,'2025-04-23 09:26:14','2025-04-23 09:24:44','김민규','원가검토에 등록한 품목들이 저장이 안되고 날라갑니다. 엑셀 수주보고서 참조하세요',547),(6,'2025-04-23 15:44:11','2025-04-23 15:42:58','김민규','모니터 중 1대는 X-BOX용',547),(7,'2025-04-23 15:44:11','2025-04-23 15:40:27','김민규','산업용 컴퓨터(인프로텍) 품목 목록에 없어서, 한솔 PC규격에 금액만 155 적용',547),(8,'2025-04-23 16:44:31','2025-04-23 16:42:58','김민규','EHP업체에게 지불해야하는 BACnet게이트웨이 2대는 외주도급으로 반영함',597),(9,'2025-04-23 16:52:16','2025-04-23 16:50:54','김민규','현장제어반, 스위치제어반(주방배기용)은 외함제작비로 각각 적용',597),(10,'2025-04-23 16:56:42','2025-04-23 16:51:55','김민규','방화댐퍼, 외주도급비용 1식 처리 (288만원현장 사이즈 재 확인후 진행필)',597),(11,'2025-04-23 16:56:42','2025-04-23 16:53:31','김민규','조명제어 에스와이시스템 (외주도급비용 1400만원)',597),(12,'2025-04-23 16:56:42','2025-04-23 16:53:42','김민규','설치비(판넬,기기류등) 외주도급비용 1식처리(910만원)',597),(13,'2025-04-23 16:56:42','2025-04-23 16:55:00','김민규','본건의 설치공사(배관/배선)는 관급자재로 발주되지 않았음',597),(14,'2025-04-23 16:56:42','2025-04-23 16:55:18','김민규','조명제어의 설치비는 에스와이 견적에 포함',597),(15,'2025-04-24 12:56:56','2025-04-24 12:55:02','김민규','기계 8025는 2개가 맞음 (내역서와 상이한건 단가상승을 이유로, NEGO 저항하기 위함)',600),(16,'2025-04-24 12:56:56','2025-04-24 12:55:30','김민규','★★인프로텍 산업용PC가 원가품목에 없어서, 한솔 단가품목으로 진행',600);
