--
-- Table structure for table `project_management`
--

DROP TABLE IF EXISTS `project_management`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `project_management` (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT 'UID',
  `created` datetime DEFAULT NULL COMMENT '생성시간',
  `contract_begin_date` datetime DEFAULT NULL COMMENT '계약기간(시작)',
  `contract_end_date` datetime DEFAULT NULL COMMENT '계약기간(종료)',
  `project_number` varchar(64) DEFAULT NULL COMMENT '프로젝트번호',
  `project_name` varchar(64) DEFAULT NULL COMMENT '프로젝트명',
  `project_date` datetime DEFAULT NULL COMMENT '등록 일자',
  `order_company` varchar(48) DEFAULT NULL COMMENT '계약업체',
  `contract_company` varchar(48) DEFAULT NULL COMMENT '원청업체',
  `project_department` varchar(48) DEFAULT NULL COMMENT '등록부서',
  `project_manager` varchar(48) DEFAULT NULL COMMENT '등록담당자',
  `contract_date` datetime DEFAULT NULL COMMENT '계약일자',
  `defect_end_date` datetime DEFAULT NULL COMMENT '하자만기',
  `contract_amount` bigint(20) DEFAULT NULL COMMENT '원청금액',
  `contract_vat_type` varchar(48) DEFAULT NULL COMMENT '원청금액부가세구분',
  `vat_type` varchar(48) DEFAULT NULL COMMENT '부가세구분',
  `completion_date` datetime DEFAULT NULL COMMENT '준공일자',
  `defect_period` varchar(48) DEFAULT NULL COMMENT '하자기간',
  `company_amount` bigint(20) DEFAULT NULL COMMENT '계약금액',
  `non_invoice` int(11) DEFAULT NULL COMMENT '미계산서',
  `company_vat_type` varchar(48) DEFAULT NULL COMMENT '계약금액부가세구분',
  `subcontracting_rate` varchar(48) DEFAULT NULL COMMENT '하도급율',
  `progress_status` varchar(48) DEFAULT NULL COMMENT '진행단계',
  `project_important` varchar(48) DEFAULT NULL COMMENT '중요',
  `location` varchar(128) DEFAULT NULL COMMENT '현장주소',
  `total_progress` int(11) DEFAULT NULL COMMENT '일정관리 전체진행률',
  `modify_manager` varchar(48) DEFAULT NULL COMMENT '최종수정자',
  `modify_date` datetime DEFAULT NULL COMMENT '최종수정일자',
  `fk_business_id` int(11) DEFAULT NULL COMMENT '영업 FK',
  `fk_excution_plan_id` int(11) DEFAULT NULL COMMENT '실행계획 FK',
  `fk_company_id` int(11) DEFAULT NULL COMMENT '회사 FK',
  PRIMARY KEY (`id`),
  KEY `fk_business_id` (`fk_business_id`),
  KEY `fk_company_id` (`fk_company_id`),
  CONSTRAINT `project_management_ibfk_1` FOREIGN KEY (`fk_business_id`) REFERENCES `project_business` (`id`),
  CONSTRAINT `project_management_ibfk_2` FOREIGN KEY (`fk_company_id`) REFERENCES `companies` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=95 DEFAULT CHARSET=utf8 COLLATE=utf8_general_ci COMMENT='프로젝트관리(프로젝트)';
/*!40101 SET character_set_client = @saved_cs_client */;

