INSERT INTO `project_notice` VALUES (5,'2025-04-14 13:39:02','PMIS 운영 관련 건','2025-03-01 13:34:33','2025-05-31 13:34:33',1,'<p><strong style=\"font-size: 14pt;\">그동안 개선 작업을 진행했던 PMIS 가 오픈되었습니다.</strong></p><p><br></p><p><strong style=\"font-size: 14pt;\">각 부서별로 현업 업무를 PMIS에 적용해 보시고 개선이 필요한 사항들은 정리해서 회신을 주시기 바랍니다.</strong></p><p><br></p><p><strong style=\"font-size: 14pt;\">영업건등록 채번은 기존의 채번룰에 따라서 채번을 하시고 등록 진행을 바랍니다.</strong></p><p><strong style=\"font-size: 14pt;\">(예, 25001 형식으로)</strong></p>','박길현',1);
