--
-- Table structure for table `setup_basic_stock`
--

DROP TABLE IF EXISTS `setup_basic_stock`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `setup_basic_stock` (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT 'UID',
  `created` datetime DEFAULT NULL COMMENT '생성시간',
  `wh_code` varchar(48) DEFAULT NULL COMMENT '창고코드',
  `item_code` varchar(48) DEFAULT NULL COMMENT '품목코드',
  `basic_stock` int(11) DEFAULT NULL COMMENT '기초재고',
  `current_stock` int(11) DEFAULT NULL COMMENT '현재고',
  `available_stock` int(11) DEFAULT NULL COMMENT '가용재고',
  `item_unit_price` float DEFAULT 0 COMMENT '단가',
  `item_price` decimal(12,2) DEFAULT 0.00 COMMENT '금액',
  `etc` text DEFAULT NULL COMMENT '비고',
  `fk_company_id` int(11) DEFAULT NULL COMMENT '회사 FK',
  PRIMARY KEY (`id`),
  KEY `wh_code` (`wh_code`),
  KEY `item_code` (`item_code`),
  KEY `fk_company_id` (`fk_company_id`),
  CONSTRAINT `setup_basic_stock_ibfk_1` FOREIGN KEY (`wh_code`) REFERENCES `base_warehouse` (`wh_code`),
  CONSTRAINT `setup_basic_stock_ibfk_2` FOREIGN KEY (`item_code`) REFERENCES `base_item` (`item_code`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `setup_basic_stock_ibfk_3` FOREIGN KEY (`fk_company_id`) REFERENCES `companies` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=19178 DEFAULT CHARSET=utf8 COLLATE=utf8_general_ci COMMENT='셋업관리(기초재고관리)';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `setup_basic_stock`
--

