--
-- Table structure for table `setup_menu`
--

DROP TABLE IF EXISTS `setup_menu`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `setup_menu` (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT 'UID',
  `created` datetime DEFAULT NULL COMMENT '생성시간',
  `parent_id` int(11) DEFAULT NULL COMMENT '상위 메뉴 아이디',
  `menu_name` varchar(48) DEFAULT NULL COMMENT '메뉴명',
  `menu_depth` int(11) DEFAULT NULL COMMENT '메뉴레벨',
  `menu_order` int(11) DEFAULT NULL COMMENT '표시순서',
  `menu_enable` tinyint(1) DEFAULT NULL COMMENT '사용여부',
  `menu_initial` varchar(10) DEFAULT NULL COMMENT '자동채번이니셜',
  `menu_initial_enable` tinyint(1) DEFAULT NULL COMMENT '자동채번이니셜사용여부',
  `menu_format` int(11) DEFAULT NULL COMMENT '연월일표기유형',
  `menu_middle_letter` varchar(5) DEFAULT NULL COMMENT '중간자',
  `menu_last_digit` int(11) DEFAULT NULL COMMENT '뒷자리수',
  `menu_function` int(11) DEFAULT NULL COMMENT '메뉴별기능목록',
  `path` varchar(256) DEFAULT NULL COMMENT 'View Path',
  `etc` text DEFAULT NULL COMMENT '비고',
  `fk_company_id` int(11) DEFAULT NULL COMMENT '회사 FK',
  PRIMARY KEY (`id`),
  KEY `fk_company_id` (`fk_company_id`),
  CONSTRAINT `setup_menu_ibfk_1` FOREIGN KEY (`fk_company_id`) REFERENCES `companies` (`id`),
  CONSTRAINT `CONSTRAINT_1` CHECK (`menu_enable` in (0,1)),
  CONSTRAINT `CONSTRAINT_2` CHECK (`menu_initial_enable` in (0,1))
) ENGINE=InnoDB AUTO_INCREMENT=154 DEFAULT CHARSET=utf8 COLLATE=utf8_general_ci COMMENT='셋업관리(메뉴관리,자동체번관리)';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `setup_menu`
--

LOCK TABLES `setup_menu` WRITE;
/*!40000 ALTER TABLE `setup_menu` DISABLE KEYS */;
