--
-- Table structure for table `setup_produce_cost`
--

DROP TABLE IF EXISTS `setup_produce_cost`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `setup_produce_cost` (
  `year` varchar(48) NOT NULL COMMENT '적용연도',
  `subfix` varchar(48) NOT NULL COMMENT '구분',
  `name` varchar(48) DEFAULT NULL COMMENT '제조구분',
  `labor_cost` int(11) DEFAULT NULL COMMENT '노무비단가(원)',
  `produce_cost_rate` int(11) DEFAULT NULL COMMENT '제조경비(%)',
  `operating_cost_rate` int(11) DEFAULT NULL COMMENT '판관비(%)',
  `fk_company_id` int(11) NOT NULL COMMENT '회사 FK',
  PRIMARY KEY (`year`,`subfix`,`fk_company_id`),
  KEY `fk_company_id` (`fk_company_id`),
  CONSTRAINT `setup_produce_cost_ibfk_1` FOREIGN KEY (`fk_company_id`) REFERENCES `companies` (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COLLATE=utf8_general_ci COMMENT='셋업관리(년도별 원가구성 요율관리)';
/*!40101 SET character_set_client = @saved_cs_client */;

